            </div>
            <div class="col-md-6">
                <label class="form-label">Phone</label>
                <input type="tel" class="form-control" @bind="Reference.Phone" placeholder="Phone number" />
            </div>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public ReferenceModel Reference { get; set; } = default!;
    [Parameter] public int Index { get; set; }
    [Parameter] public bool CanRemove { get; set; }
    [Parameter] public EventCallback OnRemove { get; set; }
}

@using sv_a4906e9bf7874788b636c5219f18c8eb.Models
@inject IApplicationService AppService

<h4 class="mb-4">Personal Information</h4>

<div class="row g-3">
    <div class="col-md-6">
        <label class="form-label">Full Name <span class="text-danger">*</span></label>
        <input class="form-control @ValidationClass("FullName")" @bind="Model.FullName" placeholder="John Doe" />
        @if (_errors.TryGetValue("FullName", out var fullNameError))
        {
            <div class="invalid-feedback d-block">@fullNameError</div>
        }
    </div>
    <div class="col-md-6">
        <label class="form-label">Email <span class="text-danger">*</span></label>
        <input type="email" class="form-control @ValidationClass("Email")" @bind="Model.Email" placeholder="email@example.com" />
        @if (_errors.TryGetValue("Email", out var emailError))
        {
            <div class="invalid-feedback d-block">@emailError</div>
        }
    </div>
    <div class="col-md-6">
        <label class="form-label">Phone <span class="text-danger">*</span></label>
        <input type="tel" class="form-control @ValidationClass("Phone")" @bind="Model.Phone" placeholder="(555) 123-4567" />
        @if (_errors.TryGetValue("Phone", out var phoneError))
        {
            <div class="invalid-feedback d-block">@phoneError</div>
        }
    </div>
    <div class="col-md-6">
        <label class="form-label">Address <span class="text-danger">*</span></label>
        <input class="form-control @ValidationClass("Address")" @bind="Model.Address" placeholder="123 Main St, City, State" />
        @if (_errors.TryGetValue("Address", out var addressError))
        {
            <div class="invalid-feedback d-block">@addressError</div>
        }
    </div>
</div>

<div class="d-flex justify-content-end mt-4">
    <button class="btn btn-primary" @onclick="HandleNext" disabled="@_isValidating">
        @if (_isValidating)
        {
            <span class="spinner-border spinner-border-sm me-1"></span>
            <span>Validating...</span>
        }
        else
        {
            <span>Next &#8594;</span>
        }
    </button>
</div>

@code {
    [Parameter, EditorRequired] public PersonalInfoModel Model { get; set; } = default!;
    [Parameter] public EventCallback OnNext { get; set; }

    private readonly Dictionary<string, string> _errors = new();
    private bool _isValidating;

    private string ValidationClass(string field) =>
        _errors.ContainsKey(field) ? "is-invalid" : "";

    private async Task HandleNext()
    {
        _errors.Clear();

        if (string.IsNullOrWhiteSpace(Model.FullName))
            _errors["FullName"] = "Full name is required.";
        if (string.IsNullOrWhiteSpace(Model.Email))
            _errors["Email"] = "Email is required.";
        if (string.IsNullOrWhiteSpace(Model.Phone))
            _errors["Phone"] = "Phone number is required.";
        if (string.IsNullOrWhiteSpace(Model.Address))
            _errors["Address"] = "Address is required.";

        if (_errors.Count > 0) return;

        _isValidating = true;
        try
        {
            var isValid = await AppService.ValidateEmailAsync(Model.Email);
            if (!isValid)
            {
                _errors["Email"] = "Please enter a valid email address.";
                return;
            }
            await OnNext.InvokeAsync();
        }
        finally
        {
            _isValidating = false;
        }
    }
}

@using sv_a4906e9bf7874788b636c5219f18c8eb.Models

<h4 class="mb-4">Work History</h4>

@for (int i = 0; i < Entries.Count; i++)
{
    var index = i;
    <WorkEntryForm Entry="Entries[index]" Index="index"
                   CanRemove="Entries.Count > 1"
                   OnRemove="() => RemoveEntry(index)" />
}

<button type="button" class="btn btn-outline-primary mb-3" @onclick="AddEntry">
    + Add Another Position
</button>

@if (_error is not null)
{
    <div class="alert alert-danger">@_error</div>
}

<div class="d-flex justify-content-between mt-4">
    <button class="btn btn-outline-secondary" @onclick="OnBack">&#8592; Back</button>
    <button class="btn btn-primary" @onclick="HandleNext">Next &#8594;</button>
</div>

@code {
    [Parameter, EditorRequired] public List<WorkEntryModel> Entries { get; set; } = default!;
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private string? _error;

    private void AddEntry() => Entries.Add(new WorkEntryModel());

    private void RemoveEntry(int index)
    {
        if (Entries.Count > 1)
            Entries.RemoveAt(index);
    }

    private async Task HandleNext()
    {
        _error = null;

        foreach (var entry in Entries)
        {
            if (string.IsNullOrWhiteSpace(entry.Company) || string.IsNullOrWhiteSpace(entry.Title))
            {
                _error = "Each position must have a company name and job title.";
                return;
            }
            if (entry.StartDate is null)
            {
                _error = "Each position must have a start date.";
                return;
            }
        }

        await OnNext.InvokeAsync();
    }
}

@using sv_a4906e9bf7874788b636c5219f18c8eb.Models

<h4 class="mb-4">References</h4>

@for (int i = 0; i < References.Count; i++)
{
    var index = i;
    <ReferenceForm Reference="References[index]" Index="index"
                   CanRemove="References.Count > 2"
                   OnRemove="() => RemoveReference(index)" />
}

@if (References.Count < 3)
{
    <button type="button" class="btn btn-outline-primary mb-3" @onclick="AddReference">
        + Add Reference
    </button>
}

@if (_error is not null)
{
    <div class="alert alert-danger">@_error</div>
}

<div class="d-flex justify-content-between mt-4">
    <button class="btn btn-outline-secondary" @onclick="OnBack">&#8592; Back</button>
    <button class="btn btn-primary" @onclick="HandleNext">Next &#8594;</button>
</div>

@code {
    [Parameter, EditorRequired] public List<ReferenceModel> References { get; set; } = default!;
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private string? _error;

    private void AddReference()
    {
        if (References.Count < 3)
            References.Add(new ReferenceModel());
    }

    private void RemoveReference(int index)
    {
        if (References.Count > 2)
            References.RemoveAt(index);
    }

    private async Task HandleNext()
    {
        _error = null;

        foreach (var r in References)
        {
            if (string.IsNullOrWhiteSpace(r.Name) || string.IsNullOrWhiteSpace(r.Email))
            {
                _error = "Each reference must have a name and email address.";
                return;
            }
        }

        await OnNext.InvokeAsync();
    }
}

@using sv_a4906e9bf7874788b636c5219f18c8eb.Models

<h4 class="mb-4">Cover Letter</h4>

<div class="mb-3">
    <textarea class="form-control" rows="12"
              @bind="Model.Text" @bind:event="oninput"
              placeholder="Write your cover letter here..."
              maxlength="@CoverLetterModel.MaxLength"></textarea>
