{"path": "/tmp/sv-a4906e9bf7874788b636c5219f18c8eb/Services/ApplicationService.cs", "file_text": "using sv_a4906e9bf7874788b636c5219f18c8eb.Models;

namespace sv_a4906e9bf7874788b636c5219f18c8eb.Services;

public class ApplicationService : IApplicationService
{
    private static int _nextId = 1000;

    public async Task<int> SubmitApplicationAsync(JobApplication application)
    {
        await Task.Delay(1500);
        return Interlocked.Increment(ref _nextId);
    }

    public async Task<bool> ValidateEmailAsync(string email)
    {
        await Task.Delay(500);
        return !string.IsNullOrWhiteSpace(email) && email.Contains('@') && email.Contains('.');
    }
}
"}

{"path": "/tmp/sv-a4906e9bf7874788b636c5219f18c8eb/Components/Pages/Apply/StepIndicator.razor", "file_text": "@using sv_a4906e9bf7874788b636c5219f18c8eb.Models

<nav aria-label="Application steps">
    <ol class="list-unstyled d-flex align-items-start justify-content-between mb-4 p-0">
        @for (int i = 0; i < _stepNames.Length; i++)
        {
            var step = i + 1;
            var state = GetStepState(step);
            var isClickable = step <= MaxStepReached && step != CurrentStep;

            <li class="text-center step-item @(isClickable ? "clickable" : "")"
                role="@(isClickable ? "button" : "")"
                @onclick="() => HandleClick(step)">
                <div class="step-circle mx-auto mb-1 rounded-circle d-flex align-items-center justify-content-center
                    @(state switch {
                        "active" => "bg-primary text-white",
                        "completed" => "bg-success text-white",
                        _ => "bg-light text-muted border"
                    })">
                    @if (state == "completed")
                    {
                        <span>&#10003;</span>
                    }
                    else
                    {
                        <span>@step</span>
                    }
                </div>
                <small class="@(state switch {
                    "active" => "fw-bold text-primary",
                    "completed" => "text-success",
                    _ => "text-muted"
                })">
                    @_stepNames[i]
                </small>
            </li>

            @if (i < _stepNames.Length - 1)
            {
                <li class="flex-grow-1 align-self-center" style="margin-top: -12px;">
                    <div class="@(step < MaxStepReached ? "bg-success" : "bg-light")"
                         style="height: 2px;"></div>
                </li>
            }
        }
    </ol>
</nav>

@code {
    private static readonly string[] _stepNames =
        ["Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"];

    [Parameter, EditorRequired] public int CurrentStep { get; set; }
    [Parameter] public int MaxStepReached { get; set; }
    [Parameter] public EventCallback<int> OnStepClicked { get; set; }

    private string GetStepState(int step) =>
        step == CurrentStep ? "active" :
        step < MaxStepReached ? "completed" :
        "pending";

    private async Task HandleClick(int step)
    {
        if (step <= MaxStepReached && step != CurrentStep)
            await OnStepClicked.InvokeAsync(step);
    }
}
"}

