{"path": "/tmp/sv-a4906e9bf7874788b636c5219f18c8eb/Components/Pages/Apply/Apply.razor", "file_text": "@page "/apply"
@rendermode InteractiveServer
@using sv_a4906e9bf7874788b636c5219f18c8eb.Models
@inject IApplicationService AppService

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h2 class="text-center mb-4">Job Application</h2>

    @if (_submittedId is not null)
    {
        <div class="text-center py-5">
            <div class="mb-3">
                <span class="display-1 text-success">&#10003;</span>
            </div>
            <h3>Application Submitted!</h3>
            <p class="lead">Your application ID is <strong>#@_submittedId</strong></p>
            <p class="text-muted">We'll review your application and get back to you soon.</p>
        </div>
    }
    else
    {
        <StepIndicator CurrentStep="_currentStep" MaxStepReached="_maxStepReached"
                       OnStepClicked="GoToStep" />

        @switch (_currentStep)
        {
            case 1:
                <PersonalInfoStep Model="_personal" OnNext="NextStep" />
                break;
            case 2:
                <WorkHistoryStep Entries="_workEntries" OnNext="NextStep" OnBack="PrevStep" />
                break;
            case 3:
                <ReferencesStep References="_references" OnNext="NextStep" OnBack="PrevStep" />
                break;
            case 4:
                <CoverLetterStep Model="_coverLetter" OnNext="NextStep" OnBack="PrevStep" />
                break;
            case 5:
                <ReviewStep Personal="_personal" WorkEntries="_workEntries"
                            References="_references" CoverLetter="@_coverLetter.Text"
                            IsSubmitting="_isSubmitting"
                            OnBack="PrevStep" OnSubmit="HandleSubmit" OnEditStep="GoToStep" />
                break;
        }
    }
</div>

@code {
    private int _currentStep = 1;
    private int _maxStepReached = 1;
    private int? _submittedId;
    private bool _isSubmitting;

    private readonly PersonalInfoModel _personal = new();
    private readonly List<WorkEntryModel> _workEntries = [new()];
    private readonly List<ReferenceModel> _references = [new(), new()];
    private readonly CoverLetterModel _coverLetter = new();

    private void NextStep()
    {
        _currentStep++;
        _maxStepReached = Math.Max(_maxStepReached, _currentStep);
    }

    private void PrevStep() => _currentStep--;

    private void GoToStep(int step) => _currentStep = step;

    private async Task HandleSubmit()
    {
        _isSubmitting = true;
        try
        {
            var application = new JobApplication(
                new PersonalInfo(_personal.FullName, _personal.Email, _personal.Phone, _personal.Address),
                new WorkHistory(_workEntries.Select(e => new WorkEntry(
                    e.Company, e.Title, e.StartDate ?? DateTime.MinValue,
                    e.IsCurrent ? null : e.EndDate, e.Description)).ToList()),
                _references.Select(r => new Reference(r.Name, r.Relationship, r.Email, r.Phone)).ToList(),
                _coverLetter.Text
            );

            _submittedId = await AppService.SubmitApplicationAsync(application);
        }
        finally
        {
            _isSubmitting = false;
        }
    }
}
"}

