@using sv_a4906e9bf7874788b636c5219f18c8eb.Models

<h4 class="mb-4">Cover Letter</h4>

<div class="mb-3">
    <textarea class="form-control" rows="12"
              @bind="Model.Text" @bind:event="oninput"
              placeholder="Write your cover letter here..."
              maxlength="@CoverLetterModel.MaxLength"></textarea>
    <div class="form-text text-end">
        @Model.Text.Length / @CoverLetterModel.MaxLength characters
    </div>
</div>

<div class="d-flex justify-content-between mt-4">
    <button class="btn btn-outline-secondary" @onclick="OnBack">&#8592; Back</button>
    <button class="btn btn-primary" @onclick="OnNext">Next &#8594;</button>
</div>

@code {
    [Parameter, EditorRequired] public CoverLetterModel Model { get; set; } = default!;
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }
}

@using sv_a4906e9bf7874788b636c5219f18c8eb.Models

<h4 class="mb-4">Review &amp; Submit</h4>

<div class="card mb-3">
    <div class="card-header d-flex justify-content-between align-items-center">
        <h5 class="mb-0">Personal Information</h5>
        <button class="btn btn-link btn-sm p-0" @onclick='() => OnEditStep.InvokeAsync(1)'>Edit</button>
    </div>
    <div class="card-body">
        <dl class="row mb-0">
            <dt class="col-sm-3">Full Name</dt>
            <dd class="col-sm-9">@Personal.FullName</dd>
            <dt class="col-sm-3">Email</dt>
            <dd class="col-sm-9">@Personal.Email</dd>
            <dt class="col-sm-3">Phone</dt>
            <dd class="col-sm-9">@Personal.Phone</dd>
            <dt class="col-sm-3">Address</dt>
            <dd class="col-sm-9">@Personal.Address</dd>
        </dl>
    </div>
</div>

<div class="card mb-3">
    <div class="card-header d-flex justify-content-between align-items-center">
        <h5 class="mb-0">Work History</h5>
        <button class="btn btn-link btn-sm p-0" @onclick='() => OnEditStep.InvokeAsync(2)'>Edit</button>
    </div>
    <div class="card-body">
        @foreach (var entry in WorkEntries)
        {
            <div class="mb-3">
                <h6 class="mb-1">@entry.Title at @entry.Company</h6>
                <p class="text-muted mb-1">
                    @(entry.StartDate?.ToString("MMM yyyy") ?? "N/A")
                    &mdash;
                    @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy") ?? "N/A")
                </p>
                @if (!string.IsNullOrWhiteSpace(entry.Description))
                {
                    <p class="mb-0">@entry.Description</p>
                }
            </div>
        }
    </div>
</div>

<div class="card mb-3">
    <div class="card-header d-flex justify-content-between align-items-center">
        <h5 class="mb-0">References</h5>
        <button class="btn btn-link btn-sm p-0" @onclick='() => OnEditStep.InvokeAsync(3)'>Edit</button>
    </div>
    <div class="card-body">
        @foreach (var r in References)
        {
            <div class="mb-2">
                <strong>@r.Name</strong> &mdash; @r.Relationship<br />
                <span class="text-muted">
                    @r.Email
                    @if (!string.IsNullOrWhiteSpace(r.Phone))
                    {
                        <span> &bull; @r.Phone</span>
                    }
                </span>
            </div>
        }
    </div>
</div>

<div class="card mb-3">
    <div class="card-header d-flex justify-content-between align-items-center">
        <h5 class="mb-0">Cover Letter</h5>
        <button class="btn btn-link btn-sm p-0" @onclick='() => OnEditStep.InvokeAsync(4)'>Edit</button>
    </div>
    <div class="card-body">
        @if (string.IsNullOrWhiteSpace(CoverLetter))
        {
            <p class="text-muted fst-italic mb-0">No cover letter provided.</p>
        }
        else
        {
            <p class="mb-0" style="white-space: pre-wrap;">@CoverLetter</p>
        }
    </div>
</div>

<div class="d-flex justify-content-between mt-4">
    <button class="btn btn-outline-secondary" @onclick="OnBack">&#8592; Back</button>
    <button class="btn btn-success btn-lg" @onclick="OnSubmit" disabled="@IsSubmitting">
        @if (IsSubmitting)
        {
            <span class="spinner-border spinner-border-sm me-1"></span>
            <span>Submitting...</span>
        }
        else
        {
            <span>Submit Application</span>
        }
    </button>
</div>

@code {
    [Parameter, EditorRequired] public PersonalInfoModel Personal { get; set; } = default!;
    [Parameter, EditorRequired] public List<WorkEntryModel> WorkEntries { get; set; } = default!;
    [Parameter, EditorRequired] public List<ReferenceModel> References { get; set; } = default!;
    [Parameter] public string CoverLetter { get; set; } = "";
    [Parameter] public bool IsSubmitting { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }
    [Parameter] public EventCallback OnSubmit { get; set; }
    [Parameter] public EventCallback<int> OnEditStep { get; set; }
}

@page "/apply"
@rendermode InteractiveServer
@using sv_a4906e9bf7874788b636c5219f18c8eb.Models
@inject IApplicationService AppService

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h2 class="text-center mb-4">Job Application</h2>

    @if (_submittedId is not null)
    {
        <div class="text-center py-5">
            <div class="mb-3">
                <span class="display-1 text-success">&#10003;</span>
            </div>
            <h3>Application Submitted!</h3>
            <p class="lead">Your application ID is <strong>#@_submittedId</strong></p>
            <p class="text-muted">We'll review your application and get back to you soon.</p>
        </div>
    }
    else
    {
        <StepIndicator CurrentStep="_currentStep" MaxStepReached="_maxStepReached"
                       OnStepClicked="GoToStep" />

        @switch (_currentStep)
        {
            case 1:
                <PersonalInfoStep Model="_personal" OnNext="NextStep" />
                break;
            case 2:
                <WorkHistoryStep Entries="_workEntries" OnNext="NextStep" OnBack="PrevStep" />
                break;
            case 3:
                <ReferencesStep References="_references" OnNext="NextStep" OnBack="PrevStep" />
                break;
            case 4:
                <CoverLetterStep Model="_coverLetter" OnNext="NextStep" OnBack="PrevStep" />
                break;
            case 5:
                <ReviewStep Personal="_personal" WorkEntries="_workEntries"
                            References="_references" CoverLetter="@_coverLetter.Text"
                            IsSubmitting="_isSubmitting"
